class Solution {
public:
    int numPairsDivisibleBy60(vector<int>& time) {
        vector<int> count(60, 0);
        int pairs = 0;
        for (int t : time) {
            int remainder = t % 60;
            pairs += count[(60 - remainder) % 60];
            count[remainder]++;
        }
        return pairs;
    }
};
